configChanged.componentPropsAllowConfig.transformDataO:
function transformData(formData) {
  if (!Array.isArray(formData.LHSX_KD_DV)) return formData;

  const transformed = {
    ...formData,
    LHSX_KD_DV: formData.LHSX_KD_DV.map((item) => {
      const newItem = { ...item };

      for (const key in item) {
        if (
          key.endsWith('.#cb#') &&
          typeof item[key] === 'object' &&
          item[key] !== null &&
          item[key].checked === true
        ) {
          newItem[key] = true;
        }
      }

      return newItem;
    }),
  };

  return transformed;
}
